module RefModule (
  input clk,
  input rst,
  input load,
  input [2:0] load_value,
  output reg [2:0] count);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 3'b111;
    else if (load)
        count <= load_value;
    else
        count <= count - 1;
end
endmodule
